+      status: "done",
+      runId: params.entry.runId,
+      sessionKey: params.entry.childSessionKey,
+      text: `${resolveSubagentLabel(params.entry)} is already finished.`,
+    };
+  }
+  if (params.controller.callerSessionKey === params.entry.childSessionKey) {
+    return {
